from datetime import datetime, timedelta

current_date_input = input()
tasks = []

while True:
    task_input = input()
    if task_input == 'end':
        break
    tasks.append(task_input)

current_date = datetime.strptime(current_date_input, "%Y-%m-%d")
end_of_week = current_date + timedelta(days=7)

due_tasks = []

for task in tasks:
    description, due_date_str = task.split(", ")
    due_date = datetime.strptime(due_date_str, "%Y-%m-%d")

    if current_date <= due_date <= end_of_week:
        due_tasks.append((description, due_date_str))

if due_tasks:
    print("Tasks due with in the next 7 days:")
    for i, (description, due_date_str) in enumerate(due_tasks, start=1):
        print(f"{i}. {description} - Due on {due_date_str}")
else:
    print("No tasks due with in the next 7 days.")
